#include <iostream>

void swapValues(int a, int b);

int main() {
    int num1, num2;
    std::cin >> num1 >> num2;
    std::cout << "Before swap: a = " << num1 << ", b = " << num2 << std::endl;
    swapValues(num1, num2);
    std::cout << "After swap: a = " << num1 << ", b = " << num2 << std::endl;
    return 0;
}
